class Solution {
public:
    bool equalFrequency(string word) {
        unordered_map<char, int> freq;
        for (char c : word) {
            freq[c]++;
        }
        int uniqueChars = freq.size();
        if (uniqueChars == 1) {
            return true;
        }
        for (int i = 0; i < word.size(); i++) {
            char c = word[i];
            freq[c]--;
            if (all_of(freq.begin(), freq.end(), [](auto& pair) { return pair.second == word.size() / uniqueChars; })) {
                return true;
            }
            freq[c]++;
        }
        return false;
    }
};
```
